    -webkit-backdrop-filter: blur(8px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 50%;
    color: rgba(255, 255, 255, 0.7);
    font-size: 16px;
    line-height: 1;
    cursor: pointer;
    transition: background 0.2s, color 0.2s;
    padding: 0;
    font-family: inherit;
}

.galaxyPreviewClose:hover {
    background: rgba(0, 0, 0, 0.6);
    color: #fff;
}

.galaxyPreviewBg {
    height: 120px;
    border-radius: 16px 16px 0 0;
    background-size: cover;
    background-position: center;
    background-color: rgba(95, 146, 255, 0.12);
}

.galaxyPreviewContent {
    padding: 0 20px 20px;
    display: flex;
    flex-direction: column;
    align-items: center;
}

.galaxyPreviewAvatar {
    width: 56px;
    height: 56px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid rgba(255, 255, 255, 0.15);
    margin-top: -28px;
    background: #0a0e1a;
}

.galaxyPreviewHeading {
    font-size: 15px;
    font-weight: 600;
    color: rgba(255, 255, 255, 0.85);
    margin-top: 10px;
    text-align: center;
}

.galaxyPreviewBio {
    font-size: 13px;
    line-height: 1.5;
    color: rgba(255, 255, 255, 0.5);
    margin-top: 8px;
    text-align: center;
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.galaxyPreviewVisitBtn {
    display: inline-block;
    margin-top: 16px;
    padding: 8px 22px;
    background: rgba(95, 146, 255, 0.15);
    border: 1px solid rgba(95, 146, 255, 0.4);
    border-radius: 10px;
    color: #5f92ff;
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.galaxyPreviewVisitBtn:hover {
    background: rgba(95, 146, 255, 0.25);
    border-color: rgba(95, 146, 255, 0.6);
}

/* Minimap */
.minimap {
    position: absolute;
    bottom: 16px;
    left: 16px;
    z-index: 1010;
    width: 160px;
    height: 160px;
    border-radius: 10px;
    cursor: crosshair;
    pointer-events: auto;
    transition: opacity 0.2s;
}

.minimap:hover {
    opacity: 0.95;
}

/* Wormhole warp overlay */
.warpOverlay {
    position: absolute;
    inset: 0;
    z-index: 10;
    pointer-events: none;
    background: radial-gradient(
        ellipse at center,
        transparent 20%,
        rgba(95, 146, 255, 0.15) 60%,
        rgba(0, 0, 0, 0.6) 100%
    );
    animation: warpPulse 1.8s ease-in-out forwards;
}

@keyframes warpPulse {
    0%   { opacity: 0; }
    15%  { opacity: 1; }
    85%  { opacity: 1; }
    100% { opacity: 0; }
}

@media (max-width: 600px) {
    .previewPanel {
        width: auto;
        right: 16px;
        left: 16px;
        bottom: 12px;
        max-height: 260px;
        box-sizing: border-box;
    }

    .backButton {
        top: 12px;
        left: 12px;
        padding: 8px 14px;
        font-size: 13px;
    }

    .coordsLabel {
        bottom: auto;
        top: 12px;
        right: 12px;
        left: auto;
    }

    .minimap {
        width: 100px;
        height: 100px;
        bottom: 12px;
        left: 12px;
    }

    .galaxyPreviewPanel {
        width: calc(100% - 32px);
        right: 16px;
        left: 16px;
        bottom: 12px;
        max-height: 300px;
    }
}

